mapper.select:
select count(*) from leave_application
where student_id = #{studentId}
and status = '1'
and DATE_FORMAT(start_time, '%Y-%m') = #{yearMonth}

select 'leave' as application_type, la.leave_id as id, la.duty_id, la.student_id, la.student_name, null as related_student_id, null as related_student_name, la.venue_id, v.venue_name, la.start_time, la.end_time, la.reason, la.proof_image, case la.status when '0' then 'pending' when '1' then 'approved' when '2' then 'rejected' when '3' then 'cancelled' else la.status end as status, la.status as status_code, la.approve_time, la.approve_remark, la.cancel_time, la.cancel_reason, la.created_at from leave_application la left join venue v on la.venue_id = v.venue_id where la.student_id = #{studentId}
and la.status = '0' and la.status = '1' and la.status = '2' and la.status = '3' and la.status = #{status}
order by la.created_at desc

mapper.update:
update leave_application
set status = '3',
    cancel_time = #{cancelTime},
    cancel_reason = #{cancelReason},
    updated_at = #{cancelTime}
where leave_id = #{leaveId}
  and student_id = #{studentId}
  and status = '0'
